export function HeroLaptopArt({ className }: { className?: string }) {
  return (
    <svg
      viewBox="0 0 576 687.6"
      xmlns="http://www.w3.org/2000/svg"
      role="img"
      aria-label="Illustration of leafy vines growing out of an open laptop"
      className={className ?? "h-auto w-full"}
    >
      <style>{`.hla-ms{fill:none;stroke:#fff;stroke-linecap:round;stroke-linejoin:round;stroke-dasharray:1 2;stroke-dashoffset:1;animation-name:hla-grow;animation-timing-function:cubic-bezier(.4,0,.2,1);animation-fill-mode:forwards}
.hla-sp{opacity:0;transform-box:fill-box;transform-origin:50% 50%}
.hla-bp{animation-name:hla-unblock;animation-duration:.35s;animation-fill-mode:forwards}
@keyframes hla-unblock{to{opacity:0}}
.hla-ch{opacity:0;animation:hla-chfade .9s ease .15s forwards}
.hla-ch .hla-ms{animation:none;stroke-dashoffset:0}
@keyframes hla-chfade{to{opacity:1}}
@keyframes hla-grow{to{stroke-dashoffset:0}}
@keyframes hla-spop{0%{opacity:0;transform:scale(0)}100%{opacity:1;transform:scale(1)}}
@keyframes hla-twinkle{from{opacity:1}to{opacity:.55}}
@media (prefers-reduced-motion: reduce){
.hla-ms{animation:none;stroke-dashoffset:0}
.hla-blk{display:none}
.hla-ch{animation:none;opacity:1}
.hla-sp{animation:none;opacity:1;transform:none}
}`}</style>
      <g dangerouslySetInnerHTML={{ __html: HERO_LAPTOP_ART_MARKUP }} />
    </svg>
  );
}
